async function p(s,o){const e=await fetch(s,o),n=await e.text(),t=n.trim(),i=e.headers.get("content-type")||"";if(t&&!(i.includes("application/json")||t.startsWith("{")||t.startsWith("["))){const a=t.replace(/\s+/g," ").slice(0,120);throw new Error(`API returned non-JSON response: ${a||"empty response"}`)}let r;try{r=t?JSON.parse(n):null}catch{throw new Error("API returned invalid JSON")}return{res:e,data:r}}export{p as r};
